function useFonts() {
  useEffect(() => {
    const link = document.createElement("link");
    link.href = "https://fonts.googleapis.com/css2?family=DM+Sans:ital,wght@0,300;0,400;0,500;0,600;1,400&family=DM+Mono:wght@400;500&family=Playfair+Display:wght@400;500&display=swap";
    link.rel = "stylesheet";
    document.head.appendChild(link);
  }, []);
}

// ── Icon buttons (matching the ▣ ↻ ✎ 🗑 style from screenshot) ───────────────
function IconBtn({ children, onClick, danger }) {
  const [hov, setHov] = useState(false);
  return (
    <button
      onClick={onClick}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        width: 32, height: 32,
        border: `1px solid ${hov ? (danger ? T.danger : T.text) : T.border}`,
        borderRadius: 4, background: hov && danger ? "#fef2f2" : T.surface,
        display: "flex", alignItems: "center", justifyContent: "center",
        cursor: "pointer", color: danger ? T.danger : T.text,
        fontSize: 13, transition: "all 0.15s", flexShrink: 0,
      }}
    >{children}</button>
  );
}

// ── Accordion Item (public) ───────────────────────────────────────────────────
function AccordionItem({ faq, index }) {
  const [open, setOpen] = useState(false);
  return (
    <div style={{ borderBottom: `1px solid ${T.border}` }}>
      <button
        onClick={() => setOpen(!open)}
        style={{
          width: "100%", background: "none", border: "none",
          padding: "18px 0", display: "flex", alignItems: "center",
          justifyContent: "space-between", gap: 12,
          cursor: "pointer", textAlign: "left",
        }}
      >
        <span style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <span style={{ fontFamily: T.fontMono, fontSize: 11, color: T.textXMuted, minWidth: 20 }}>
            {String(index + 1).padStart(2, "0")}
          </span>
          <span style={{ fontFamily: T.fontSans, fontSize: 17, color: T.text, fontWeight: 400, lineHeight: 1.3 }}>
            {faq.question}
          </span>
        </span>
        <span style={{
          fontFamily: T.fontMono, fontSize: 16, color: T.textMuted, flexShrink: 0,
          transform: open ? "rotate(45deg)" : "rotate(0deg)",
          transition: "transform 0.25s ease", display: "block",
        }}>+</span>
      </button>
      <div style={{ maxHeight: open ? "600px" : 0, overflow: "hidden", transition: "max-height 0.5s cubic-bezier(0.4,0,0.2,1)" }}>
        <div style={{ fontFamily: T.fontSans, fontSize: 15, color: T.textMuted, lineHeight: 1.7, paddingBottom: 18, paddingLeft: 34, margin: 0 }}>
          {(() => {
            const lines = faq.answer.split(/\n|(?=\s*[–—-]\s)/);
            const bullets = lines.map(l => l.trim()).filter(l => l.match(/^[–—-]\s/));
            if (bullets.length > 1) {
              const parts = faq.answer.split(/\n/).map(l => l.trim()).filter(Boolean);
              return (
                <ul style={{ paddingLeft: 18, margin: 0 }}>
                  {parts.map((part, i) => (
                    <li key={i} style={{ marginBottom: 6, listStyleType: "disc" }}>
                      {part.replace(/^[–—-]\s*/, "")}
                    </li>
                  ))}
                </ul>
              );
            }
            return <p style={{ margin: 0 }}>{faq.answer}</p>;
          })()}
        </div>
      </div>
    </div>
  );
}

